import java.io.*;import java.util.*;class Main{static class Pair{int s1,s2;Pair(int a,int b){s1=a;s2=b;}}static int solve(String s1,int n1,String s2,int n2){boolean[]seenChar=new boolean[256];for(char c:s1.toCharArray())seenChar[c]=true;for(char c:s2.toCharArray())if(!seenChar[c])return 0;HashMap<Integer,Pair> seen=new HashMap<>();int s1c=0,s2c=0,idx2=0,prefixS1=0,prefixS2=0,loopS1=0,loopS2=0;while(true){s1c++;for(char c:s1.toCharArray())if(c==s2.charAt(idx2)){idx2++;if(idx2==s2.length()){s2c++;idx2=0;}}if(s1c==n1)return s2c/n2;Pair p=seen.get(idx2);if(p!=null){prefixS1=p.s1;prefixS2=p.s2;loopS1=s1c-p.s1;loopS2=s2c-p.s2;break;}seen.put(idx2,new Pair(s1c,s2c));}int ans=prefixS2,remain=n1-prefixS1;ans+=(remain/loopS1)*loopS2;int rest=remain%loopS1;while(rest-->0)for(char c:s1.toCharArray())if(c==s2.charAt(idx2)){idx2++;if(idx2==s2.length()){ans++;idx2=0;}}return ans/n2;}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]v=text.split("\\s+");int idx=0,t=Integer.parseInt(v[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){String s1=v[idx++];int n1=Integer.parseInt(v[idx++]);String s2=v[idx++];int n2=Integer.parseInt(v[idx++]);if(tc>0)out.append("\n\n");out.append(solve(s1,n1,s2,n2));}System.out.print(out);}}
